__device__ void kernel_2(	int timeinst,
											fp* initvalu,
											fp* params,
											fp* finavalu,
											fp* com){

	int valu_offset_ecc;
	int valu_offset_Dyad;
	int valu_offset_SL;
	int valu_offset_Cyt;

	int params_offset_Dyad;
	int params_offset_SL;
	int params_offset_Cyt;

	int com_offset_Dyad;
	int com_offset_SL;
	int com_offset_Cyt;

	fp CaDyad;
	fp CaSL;
	fp CaCyt;

	int i;

	valu_offset_ecc = 0;
	valu_offset_Dyad = 46;
	valu_offset_SL = 61;
	valu_offset_Cyt = 76;

	params_offset_Dyad = 0;
	params_offset_SL = 5;
	params_offset_Cyt = 10;

	com_offset_Dyad = 0;
	com_offset_SL = 1;
	com_offset_Cyt = 2;

	kernel_ecc_2(	timeinst,
							initvalu,
							finavalu,
							valu_offset_ecc,
							params);

	CaDyad = initvalu[35]*1e3;

	kernel_cam_2(	timeinst,
								initvalu,
								finavalu,
								valu_offset_Dyad,
								params,
								params_offset_Dyad,
								com,
								com_offset_Dyad,
								CaDyad);

	CaSL = initvalu[36]*1e3;

	kernel_cam_2(	timeinst,
								initvalu,
								finavalu,
								valu_offset_SL,
								params,
								params_offset_SL,
								com,
								com_offset_SL,
								CaSL);

	CaCyt = initvalu[37]*1e3;

	kernel_cam_2(	timeinst,
								initvalu,
								finavalu,
								valu_offset_Cyt,
								params,
								params_offset_Cyt,
								com,
								com_offset_Cyt,
								CaCyt);

	kernel_fin_2(	timeinst,
							initvalu,
							finavalu,
							valu_offset_ecc,
							valu_offset_Dyad,
							valu_offset_SL,
							valu_offset_Cyt,
							params,
							com);

	for(i=0; i<EQUATIONS; i++){
		if (isnan(finavalu[i]) == 1){ 
			finavalu[i] = 0.0001;
		}
		else if (isinf(finavalu[i]) == 1){ 
			finavalu[i] = 0.0001;
		}
	}

}

